import { MODEL_IDS } from "../models/registry.js";

export interface AgentDefinition {
  id: string;
  name: string;
  domain: string;
  subdomain: string;
  description: string;
  systemPrompt: string;
  preferredModel: string;
  capabilities: string[];
  priority: number;
}

function a(
  id: string,
  name: string,
  domain: string,
  subdomain: string,
  description: string,
  model: string,
  capabilities: string[],
  priority = 5,
): AgentDefinition {
  return {
    id,
    name,
    domain,
    subdomain,
    description,
    systemPrompt: `You are ${name}. ${description}\n\nYour role: Analyze the given task and provide your specialized output. Be thorough, precise, and actionable. Format your response clearly with sections as needed. Focus exclusively on your domain of expertise.`,
    preferredModel: model,
    capabilities,
    priority,
  };
}

