export function getAgentsByDomain(domain: string): AgentDefinition[] {
  return AGENT_REGISTRY.filter((a) => a.domain === domain);
}

export function getAgentById(id: string): AgentDefinition | undefined {
  return AGENT_REGISTRY.find((a) => a.id === id);
}

export function searchAgents(query: string): AgentDefinition[] {
  const q = query.toLowerCase();
  return AGENT_REGISTRY.filter(
    (a) =>
      a.name.toLowerCase().includes(q) ||
      a.description.toLowerCase().includes(q) ||
      a.domain.includes(q) ||
      a.subdomain.includes(q) ||
      a.capabilities.some((c) => c.includes(q)),
  );
}

export function getAgentsForDomains(domains: string[]): AgentDefinition[] {
  if (!domains || domains.length === 0) return AGENT_REGISTRY;
  return AGENT_REGISTRY.filter((a) => domains.includes(a.domain));
}

